from flatten_config import main

def test_flatten():
    # Test case 1: Basic nesting
    config1 = {"a": {"b": 1, "c": {"d": 2}}}
    expected1 = {"a.b": 1, "a.c.d": 2}
    assert main(config1) == expected1
    print("Test 1 passed")

    # Test case 2: With prefix
    config2 = {"x": 1}
    prefix2 = "ns"
    expected2 = {"ns.x": 1}
    assert main(config2, prefix=prefix2) == expected2
    print("Test 2 passed")

    # Test case 3: Nested with prefix
    config3 = {"a": {"b": 1}}
    prefix3 = "env"
    expected3 = {"env.a.b": 1}
    assert main(config3, prefix=prefix3) == expected3
    print("Test 3 passed")

    # Test case 4: Non-dict values and lists
    config4 = {
        "str": "hello",
        "int": 42,
        "bool": True,
        "list": [1, 2, {"nested": 3}]  # Lists are NOT recursed into
    }
    expected4 = {
        "str": "hello",
        "int": 42,
        "bool": True,
        "list": [1, 2, {"nested": 3}]
    }
    assert main(config4) == expected4
    print("Test 4 passed")

if __name__ == "__main__":
    test_flatten()

